mapper.select:
SELECT s.match_user_id, SUM( IFNULL(s.total_amount, 0) - IFNULL(b.total_amount, 0) - IFNULL(s.warehouse_amount, 0) - IFNULL(b.warehouse_amount, 0) - IFNULL(s.transport_amount, 0) - IFNULL(b.transport_amount, 0) - IFNULL(s.stevedorage, 0) - IFNULL(b.stevedorage, 0) - IFNULL(s.delivery_fee, 0) - IFNULL(b.delivery_fee, 0) ) AS grossProfitAmount, SUM(IFNULL(s.total_amount, 0)) sellTotalAmount, SUM(IFNULL(s.total_number, 0)) sellTotalNumber FROM t_ctr_contract_settlement r LEFT JOIN t_ctr_contract s ON r.sell_contract_id = s.id LEFT JOIN t_ctr_contract b ON r.buy_contract_id = b.id WHERE s.contract_status != 'C' AND s.status != 'C' AND s.contract_type = 'S' AND s.business_type = 'ZY-BB' AND s.enterprise_id = 44 AND s.seal_flg = TRUE AND b.seal_flg = TRUE
AND DATE_FORMAT(s.seal_date, '%Y-%m') = #{month}
AND DATE_FORMAT(s.seal_date, '%Y') = #{year}
and s.match_user_id not in
#{hgMatchUserIdList[${index}]}
GROUP BY s.match_user_id ORDER BY grossProfitAmount DESC

SELECT result.match_user_id, SUM(IFNULL(result.grossProfitAmount, 0)) grossProfitAmount, SUM(IFNULL(result.sellTotalAmount, 0)) sellTotalAmount, SUM(IFNULL(result.sellTotalNumber, 0)) sellTotalNumber, ranking FROM ( SELECT s.match_user_id, SUM( IFNULL(s.total_amount, 0) - IFNULL(b.total_amount, 0) - IFNULL(s.warehouse_amount, 0) - IFNULL(b.warehouse_amount, 0) - IFNULL(s.transport_amount, 0) - IFNULL(b.transport_amount, 0) - IFNULL(s.stevedorage, 0) - IFNULL(b.stevedorage, 0) - IFNULL(s.delivery_fee, 0) - IFNULL(b.delivery_fee, 0) ) AS grossProfitAmount, SUM(IFNULL(s.total_amount, 0)) sellTotalAmount, SUM(IFNULL(s.total_number, 0)) sellTotalNumber, @rownum := @rownum + 1 AS ranking FROM t_ctr_contract_settlement r LEFT JOIN t_ctr_contract s ON r.sell_contract_id = s.id LEFT JOIN t_ctr_contract b ON r.buy_contract_id = b.id WHERE s.contract_status != 'C' AND s.status != 'C' AND s.contract_type = 'S' AND s.business_type = 'ZY-BB' AND s.enterprise_id = 44 AND s.seal_flg = TRUE AND b.seal_flg = TRUE
AND DATE_FORMAT(s.seal_date, '%Y-%m') = #{month}
AND DATE_FORMAT(s.seal_date, '%Y') = #{year}
and s.match_user_id not in
#{hgMatchUserIdList[${index}]}
GROUP BY s.match_user_id ORDER BY grossProfitAmount DESC ) result, (SELECT @rownum := 0) r WHERE 1=1
and result.match_user_id in
#{matchUserIdList[${index}]}

SELECT date_format(s.seal_date, '%Y-%m') month, SUM( IFNULL(s.total_amount, 0) - IFNULL(b.total_amount, 0) - IFNULL(s.warehouse_amount, 0) - IFNULL(b.warehouse_amount, 0) - IFNULL(s.transport_amount, 0) - IFNULL(b.transport_amount, 0) - IFNULL(s.stevedorage, 0) - IFNULL(b.stevedorage, 0) - IFNULL(s.delivery_fee, 0) - IFNULL(b.delivery_fee, 0) ) AS grossProfitAmount
FROM t_ctr_contract_settlement r LEFT JOIN t_ctr_contract s ON r.sell_contract_id = s.id LEFT JOIN t_ctr_contract b ON r.buy_contract_id = b.id WHERE s.contract_status != 'C' AND s.status != 'C' AND s.contract_type = 'S' AND s.business_type = 'ZY-BB' AND s.enterprise_id = 44 AND s.seal_flg = TRUE AND b.seal_flg = TRUE
and s.match_user_id not in
#{hgMatchUserIdList[${index}]}
and date_format(s.seal_date, '%Y-%m') in
#{fiveMonthList[${index}],jdbcType=VARCHAR}
and s.match_user_id in
#{matchUserIdList[${index}]}
group by date_format(s.seal_date, '%Y-%m') order by s.seal_date

SELECT * FROM (SELECT c.id, c.contract_no, c.contract_type, c.company_id, c.company_name, c.our_company_name, c.`status`, c.contract_status, c.appoint_pay_full_time, c.match_user_id, c.match_user_name, c.total_amount, c.total_number, c.dealed_amount, c.warehouse_number, c.billed_amount, c.dept_id, c.business_type, c.seal_flg, c.seal_date, c.breach_days, c.credit_cycle, c.breach_amount, c.receive_breach_amount, IFNULL(c.breach_amount, 0) - IFNULL(c.receive_breach_amount, 0) noReceiveBreachAmount, IFNULL(c.total_amount, 0) - IFNULL(c.dealed_amount, 0) + IFNULL(c.breach_amount, 0) - IFNULL(c.receive_breach_amount, 0) noReceiveTotalAmount, c.match_credit_flg, c.contract_time, c.performance_status, c.business_kind FROM t_ctr_contract c WHERE c.contract_status != 'C' AND c.STATUS != 'C' AND c.contract_type = 'S' AND c.business_type = 'ZY-BB' AND c.enterprise_id = 44 AND c.seal_flg = TRUE AND ( performance_status IN ( 'B', 'D', 'S', 'P' ) OR ( performance_status = 'N' AND DATEDIFF( appoint_pay_full_time, CURDATE()) < 7 AND DATEDIFF( appoint_pay_full_time, CURDATE()) >= 0 ) )
and c.match_user_id in
#{matchUserIdList[${index}]}
ORDER BY c.contract_time DESC) result WHERE 1=1
AND result.performance_status = #{labelCode}

SELECT sum(result.total_amount) AS totalAmount, sum(result.total_number) AS totalNumber, sum(result.dealed_amount) AS dealedAmount, sum(result.breach_amount) AS breachAmount, sum(result.noReceiveBreachAmount) AS noReceiveBreachAmount, sum(result.noReceiveTotalAmount) AS noReceiveTotalAmount FROM (SELECT c.id, c.contract_no, c.contract_type, c.company_id, c.company_name, c.our_company_name, c.`status`, c.contract_status, c.appoint_pay_full_time, c.match_user_id, c.match_user_name, c.total_amount, c.total_number, c.dealed_amount, c.warehouse_number, c.billed_amount, c.dept_id, c.business_type, c.seal_flg, c.seal_date, c.breach_days, c.credit_cycle, c.breach_amount, c.receive_breach_amount, IFNULL(c.breach_amount, 0) - IFNULL(c.receive_breach_amount, 0) noReceiveBreachAmount, IFNULL(c.total_amount, 0) - IFNULL(c.dealed_amount, 0) + IFNULL(c.breach_amount, 0) - IFNULL(c.receive_breach_amount, 0) noReceiveTotalAmount, c.match_credit_flg, c.contract_time, c.performance_status, c.business_kind FROM t_ctr_contract c WHERE c.contract_status != 'C' AND c.STATUS != 'C' AND c.contract_type = 'S' AND c.business_type = 'ZY-BB' AND c.enterprise_id = 44 AND c.seal_flg = TRUE AND ( performance_status IN ( 'B', 'D', 'S', 'P' ) OR ( performance_status = 'N' AND DATEDIFF( appoint_pay_full_time, CURDATE()) < 7 AND DATEDIFF( appoint_pay_full_time, CURDATE()) >= 0 ) )
and c.match_user_id in
#{matchUserIdList[${index}]}
ORDER BY c.contract_time DESC) result WHERE 1=1
AND result.performance_status = #{labelCode}

SELECT c.id, c.company_name, c.company_source, c.company_type, c.contact_name, c.contact_phone, c.company_category, c.industry, c.created_date FROM t_bs_company c WHERE c.company_type = #{companyType}
and c.owner_of_account_id in
#{matchUserIdList[${index}]}
AND DATE_FORMAT(c.created_date, '%Y-%m') = #{month}
AND DATE_FORMAT(c.created_date, '%Y') = #{year}
ORDER BY c.created_date DESC

SELECT c.id, c.company_name, c.company_type, c.created_date, p.updated_date piccEntryDate, p.apply_picc_date, p.apply_credit_amount piccApplyCreditAmount, c.picc_apply_status FROM t_bs_company c INNER JOIN t_picc_supplement_info p ON p.company_id = c.id WHERE c.picc_apply_credit_amount_flg = TRUE AND c.picc_apply_status = '1'
and c.match_user_id in
#{matchUserIdList[${index}]}

SELECT bc.id, bc.company_name, bc.contact_name, bc.contact_phone, bc.company_source FROM t_bs_company bc INNER JOIN t_ctr_contract con ON bc.id = con.company_id WHERE bc.company_type = #{companyType}
and bc.match_user_id in
#{matchUserIdList[${index}]}
AND con.contract_status != 'C' AND con.status != 'C' AND con.business_type = 'ZY-BB' AND con.enterprise_id = 44 AND con.contract_time >= CURDATE() - INTERVAL 2 MONTH GROUP BY bc.id

SELECT con.company_id id, MAX(con.contract_time) AS lastContractTime, MIN(con.contract_time) AS firstContractTime, SUM(con.total_amount) AS totalContractAmount FROM t_ctr_contract con WHERE con.contract_status != 'C' AND con.STATUS != 'C' AND con.business_type = 'ZY-BB' AND con.enterprise_id = 44
and con.match_user_id in
#{matchUserIdList[${index}]}
AND con.company_id IN
#{companyIdList[${index}],jdbcType=VARCHAR}
GROUP BY con.company_id
